import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"F01: 營收因子與定價權分析 — 財務分析專家審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8103_瀚荃/20260425/F01_營收因子與定價權分析.md","filePath":"審計報告庫/財務審計/8103_瀚荃/20260425/F01_營收因子與定價權分析.md"}'),n={name:"審計報告庫/財務審計/8103_瀚荃/20260425/F01_營收因子與定價權分析.md"};function d(i,t,s,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="f01-營收因子與定價權分析-—-財務分析專家審計報告" tabindex="-1">F01: 營收因子與定價權分析 — 財務分析專家審計報告 <a class="header-anchor" href="#f01-營收因子與定價權分析-—-財務分析專家審計報告" aria-label="Permalink to &quot;F01: 營收因子與定價權分析 — 財務分析專家審計報告&quot;">​</a></h1><p><strong>標的公司</strong>：8103 瀚荃 | <strong>審計日期</strong>：2026-04-25 | <strong>數據截至</strong>：FY2025（2025/12）+ 2026Q1 最新月營收</p><hr><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>營收成長或衰退的實質因子分析：是由於「銷量增加 (Volume Up)」還是「單價調整 (Price Up)」？</p><hr><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>瀚荃營收成長由<strong>產品組合升級帶動隱含單價提升（Price Mix Up）<strong>主導。FY2025 營收 33.55 億元（YoY +5.25%），毛利率從 34.77% 大幅擴張至 37.41%（+2.64pp），反映公司將產品組合從低毛利消費性連接器轉向 AI 伺服器 PSU 板端連接器，此為</strong>定價權結構性提升</strong>特徵。AI 電源占比從 FY2024 的約 15% 提升至 FY2025 的 18%，價量齊揚但以價為主。</p><hr><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>A（良）</strong> — 單價透過產品組合升級穩定提升，高毛利 AI 伺服器連接器占比持續攀高；營收成長雖溫和（+5.25%），但毛利率擴張 2.64pp 證明定價權正從「成本轉嫁型」轉向「品牌溢價型」。未達 S 級的原因：FY2025 下半年（7-8月）月營收曾出現 YoY 負成長（-2.4%、-11.16%），顯示消費性電子與網通傳統業務仍受景氣壓抑，整體營收成長動能尚非全面性擴張。</p><hr><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-驅動因子權重-driver-weight" tabindex="-1">1. 驅動因子權重 (Driver Weight) <a class="header-anchor" href="#_1-驅動因子權重-driver-weight" aria-label="Permalink to &quot;1. 驅動因子權重 (Driver Weight)&quot;">​</a></h3><p><strong>營收橋接分析（FY2024→FY2025）</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">指標</th><th style="text-align:left;">FY2024</th><th style="text-align:left;">FY2025</th><th style="text-align:left;">變動</th></tr></thead><tbody><tr><td style="text-align:left;">營收</td><td style="text-align:left;">31.88 億</td><td style="text-align:left;">33.55 億</td><td style="text-align:left;">+1.67 億 (+5.25%)</td></tr><tr><td style="text-align:left;">毛利</td><td style="text-align:left;">11.08 億</td><td style="text-align:left;">12.55 億</td><td style="text-align:left;">+1.47 億 (+13.27%)</td></tr><tr><td style="text-align:left;">毛利率</td><td style="text-align:left;">34.77%</td><td style="text-align:left;">37.41%</td><td style="text-align:left;">+2.64pp</td></tr><tr><td style="text-align:left;">營業利益</td><td style="text-align:left;">3.65 億</td><td style="text-align:left;">4.50 億</td><td style="text-align:left;">+0.85 億 (+23.3%)</td></tr></tbody></table><p><strong>價格因子貢獻測算</strong>：營收增量 1.67 億中，毛利率擴張 2.64pp 代表「單價提升貢獻」約 0.89 億元，佔總毛利增量的 60.5%；銷量貢獻約 0.58 億元，佔 39.5%。<strong>結論：價格因子 ≈ 60%，銷量 ≈ 40%，價格為主驅動力。</strong></p><p><strong>季度毛利率趨勢驗證</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">季度</th><th style="text-align:left;">毛利率</th><th style="text-align:left;">營益率</th><th style="text-align:left;">動能判讀</th></tr></thead><tbody><tr><td style="text-align:left;">2024Q1</td><td style="text-align:left;">31.67%</td><td style="text-align:left;">6.28%</td><td style="text-align:left;">低毛利消費電子為主</td></tr><tr><td style="text-align:left;">2024Q2</td><td style="text-align:left;">38.77%</td><td style="text-align:left;">15.48%</td><td style="text-align:left;">AI 伺服器出貨旺季</td></tr><tr><td style="text-align:left;">2024Q3</td><td style="text-align:left;">36.84%</td><td style="text-align:left;">15.97%</td><td style="text-align:left;">高毛利組合持續</td></tr><tr><td style="text-align:left;">2024Q4</td><td style="text-align:left;">31.20%</td><td style="text-align:left;">6.89%</td><td style="text-align:left;">季節性回落</td></tr><tr><td style="text-align:left;">2025Q1</td><td style="text-align:left;">34.15%</td><td style="text-align:left;">9.02%</td><td style="text-align:left;">組合優化，淡季不淡</td></tr><tr><td style="text-align:left;">2025Q2</td><td style="text-align:left;">37.48%</td><td style="text-align:left;">16.47%</td><td style="text-align:left;">定價權持續擴張</td></tr><tr><td style="text-align:left;">2025Q3</td><td style="text-align:left;">38.35%</td><td style="text-align:left;">15.98%</td><td style="text-align:left;">毛利率創近三年同期新高</td></tr><tr><td style="text-align:left;">2025Q4</td><td style="text-align:left;">39.14%</td><td style="text-align:left;">11.55%</td><td style="text-align:left;">毛利率創八年新高</td></tr></tbody></table><p>FY2025Q4 毛利率 39.14% 為近八年單季新高，全年毛利率 37.41% 較 FY2024 跳升 2.64pp，這是<strong>產品組合往高單價 AI 電源連接器傾斜</strong>的鐵證，非降價衝量可達成。</p><h3 id="_2-獲利品質連動-margin-linkage" tabindex="-1">2. 獲利品質連動 (Margin Linkage) <a class="header-anchor" href="#_2-獲利品質連動-margin-linkage" aria-label="Permalink to &quot;2. 獲利品質連動 (Margin Linkage)&quot;">​</a></h3><p>瀚荃毛利率擴張來自定價權提升，非成本下降：AI 伺服器 PSU 板端連接器競爭對手僅一家未上市櫃台廠，屬<strong>寡併格局</strong>，客戶轉換成本高。FY2025 網通伺服器營收佔 37%（AI 電源佔網通 50%，約 18%），FY2026 目標提升至 45-50%。ASP 提升伴隨毛利率 34.77%→37.41% 擴張，明確屬於<strong>獲利擴張型漲價</strong>。</p><h3 id="_3-未來路徑預測-future-path" tabindex="-1">3. 未來路徑預測 (Future Path) <a class="header-anchor" href="#_3-未來路徑預測-future-path" aria-label="Permalink to &quot;3. 未來路徑預測 (Future Path)&quot;">​</a></h3><p><strong>FY2026 動能</strong>：2026Q1 營收 9.10 億元（YoY +23.28%），3 月營收 3.33 億元（+25.79%），成長顯著加速。執行長楊奕康於 2026/4/10 法說會表示大電流板端連接器「被客戶追著擴產」，訂單至少看到 7 月。AI 電源占比從 FY2025 的 18%→前兩月已達 21%，全年朝 30% 邁進。新增兩大 ASIC 平台訂單放量，法人預估 FY2026 毛利率有機會站上 40%。<strong>風險</strong>：消費電子毛利偏低；東南亞新產能初期良率；原物料與匯率波動。</p><p><strong>壓力測試</strong>：若 AI 連接器單價下滑 5%，整體毛利率衝擊約 -0.9pp（18%×5%），降至約 36.5%，仍在健康水準。若 AI 出貨萎縮 10%，營收衝擊約 -1.8%，毛利率可能下降 1-2pp，營益率壓力較大。</p><hr><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="定價權穿透診斷" tabindex="-1">定價權穿透診斷 <a class="header-anchor" href="#定價權穿透診斷" aria-label="Permalink to &quot;定價權穿透診斷&quot;">​</a></h3><p>瀚荃營收成長呈「價格因子主導（60%）+ 銷量輔助（40%）」格局，為典型的<strong>產品組合升級驅動型定價權提升</strong>。</p><p><strong>定價權來源</strong>：(1) 技術護城河—高功率連接器門檻高，競爭對手僅一家，形成寡佔；(2) 客戶轉換成本—連接器一經設計進入伺服器架構（如 GB200/GB300 機櫃），更換需重新認證；(3) 需求結構性增長—機櫃功率從 12kW→110kW，用量倍數成長。</p><p><strong>警示風險</strong>：FY2025 年 7-8 月營收 YoY 分別 -2.4% 及 -11.16%，非 AI 業務仍在掙扎。全年營收成長 5.25% 遠低於指引的 15%，傳統旺季不及預期。瀚荃處於**「AI 紅利滲透期」**而非全面定價權確立期，一旦 AI 需求放緩，毛利率將快速回落。</p><p><strong>判定</strong>：處於產品組合升級的階段性定價權紅利期。定價權能否持續取決於：(1) 技術領先能否維持；(2) ASIC 客戶訂單穩定性；(3) 競爭對手追趕速度。應密切關注每季 AI 營收占比與毛利率連動—若占比提升但毛利率持平或下降，即為定價權衰退早期訊號。</p><hr><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ol><li><strong>FinMind 數據採集器</strong> — <code>revenue 8103 2023-04-25 2026-04-25 --df</code>（月營收原始數據）</li><li><strong>FinMind 數據採集器</strong> — <code>finance 8103 2023-04-25 2026-04-25 --df</code>（季損益表：營收、毛利、營業利益、稅後淨利）</li><li><strong>Python 計算腳本</strong> — <code>/tmp/hanchuan_audit_calc.py</code>（Revenue Bridge、毛利率趨勢、營益率計算）</li><li><strong>經濟日報 2026/4/10</strong> — 「瀚荃營收／3月3.32億元、年增25.79% 今年業務三箭齊發」（楊奕康法說會發言）</li><li><strong>優分析/Line Today</strong> — 「瀚荃(8103)產能都在哪？光電爆發＋AI，2025營收雙位數成長？」（AI 營收占比、光電成長預期）</li><li><strong>理財周刊</strong> — 「手握兩大SAIC訂單 瀚荃(8103)獲利衝刺」（AI PSU 板端連接器寡佔格局、FY2026 EPS 預估 6.85 元、毛利率站上 40% 預期）</li></ol>',35)])])}const y=e(n,[["render",d]]);export{x as __pageData,y as default};
